Patch Set 3:

Just for you information. Both implementations (atomic and spin_lock) basing on xadd instruction with lock prefix. The critical difference of proposed implementation can be only in first check. I agree it will be faster without lock prefix. But is case of contention we will have much more overhead from locks. For this particular case we have sanity check in upper layer which don't pass a single
if (avail <= low_water)
ptlrpc_grow_req_bufs(svcpt, 1);

#define atomic_inc_return(v)  (atomic_add_return(1, v))
static inline int atomic_add_return(int i, atomic_t *v)
{
        return i + xadd(&v->counter, i);
}

#define raw_spin_lock(lock)     _raw_spin_lock(lock)

static inline void __raw_spin_lock(raw_spinlock_t *lock)
{
        preempt_disable();
        spin_acquire(&lock->dep_map, 0, 0, _RET_IP_);
        LOCK_CONTENDED(lock, do_raw_spin_trylock, do_raw_spin_lock);
}

#define LOCK_CONTENDED(_lock, try, lock)                        \
do {                                                            \
        if (!try(_lock)) {                                      \
                lock_contended(&(_lock)->dep_map, _RET_IP_);    \
                lock(_lock);                                    \
        }                                                       \
        lock_acquired(&(_lock)->dep_map, _RET_IP_);             \
} while (0)
static inline void do_raw_spin_lock(raw_spinlock_t *lock) __acquires(lock)
{
        __acquire(lock);
        arch_spin_lock(&lock->raw_lock);
}

static __always_inline void arch_spin_lock(arch_spinlock_t *lock)
{
        __ticket_spin_lock(lock);
}

static __always_inline void __ticket_spin_lock(arch_spinlock_t *lock)
{
        register struct __raw_tickets inc = { .tail = 1 };

        inc = xadd(&lock->tickets, inc);

        for (;;) {
                if (inc.head == inc.tail)
                        break;
                cpu_relax();
                inc.head = ACCESS_ONCE(lock->tickets.head);
        }
        barrier(); /* make sure nothing creeps before the lock is taken */
}
